SELECT ro.id, ro.repair_no, ro.contract_id, ro.house_id, ro.landlord_id, ro.tenant_user_id, ro.title, ro.repair_type, ro.content, ro.is_urgent, ro.expect_visit_time, ro.attachment_url, ro.status, ro.handle_note, ro.handle_voucher_url, ro.repair_amount, ro.payment_status, ro.cancel_reason, ro.reject_reason, ro.accept_time, ro.finish_time, ro.tenant_confirm_time, ro.paid_time, ro.create_time, ro.update_time, rc.contract_no, h.name AS house_name, h.cover AS house_cover, lu.username AS landlord_name, tu.username AS tenant_name FROM repair_order ro LEFT JOIN rental_contract rc ON rc.id = ro.contract_id LEFT JOIN house h ON h.id = ro.house_id LEFT JOIN landlord l ON l.id = ro.landlord_id LEFT JOIN user lu ON lu.id = l.user_id LEFT JOIN user tu ON tu.id = ro.tenant_user_id
AND ( ro.repair_no LIKE concat('%',#{keyword},'%') OR ro.title LIKE concat('%',#{keyword},'%') OR h.name LIKE concat('%',#{keyword},'%') OR rc.contract_no LIKE concat('%',#{keyword},'%') OR lu.username LIKE concat('%',#{keyword},'%') OR tu.username LIKE concat('%',#{keyword},'%') )
AND ro.landlord_id = #{landlordId}
AND l.user_id = #{landlordUserId}
AND ro.tenant_user_id = #{tenantUserId}
AND ro.contract_id = #{contractId}
AND ro.house_id = #{houseId}
AND ro.status = #{status}
AND ro.payment_status = #{paymentStatus}
ORDER BY ro.id DESC
LIMIT #{current},#{size}

SELECT COUNT(*)
FROM repair_order ro
LEFT JOIN rental_contract rc ON rc.id = ro.contract_id
LEFT JOIN house h ON h.id = ro.house_id
LEFT JOIN landlord l ON l.id = ro.landlord_id
LEFT JOIN user lu ON lu.id = l.user_id
LEFT JOIN user tu ON tu.id = ro.tenant_user_id


        AND (
            ro.repair_no LIKE concat('%',#{keyword},'%')
            OR ro.title LIKE concat('%',#{keyword},'%')
            OR h.name LIKE concat('%',#{keyword},'%')
            OR rc.contract_no LIKE concat('%',#{keyword},'%')
            OR lu.username LIKE concat('%',#{keyword},'%')
            OR tu.username LIKE concat('%',#{keyword},'%')
        )


        AND ro.landlord_id = #{landlordId}


        AND l.user_id = #{landlordUserId}


        AND ro.tenant_user_id = #{tenantUserId}


        AND ro.contract_id = #{contractId}


        AND ro.house_id = #{houseId}


        AND ro.status = #{status}


        AND ro.payment_status = #{paymentStatus}
